import{_ as a,o,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"望京石与历史遗迹","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/badaling/wangjingshi.md","filePath":"landmarks/badaling/wangjingshi.md","lastUpdated":1784720050000}'),l={name:"landmarks/badaling/wangjingshi.md"};function n(i,t,s,g,u,d){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="望京石与历史遗迹" tabindex="-1">望京石与历史遗迹 <a class="header-anchor" href="#望京石与历史遗迹" aria-label="Permalink to &quot;望京石与历史遗迹&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1715905601923-e84750c8d01d?w=1200&amp;q=80" alt="望京石与历史遗迹"></p><blockquote><p>一块巨石，一道摩崖，一条&quot;人&quot;字形铁路——八达岭脚下，藏着长城之外的另一部近代史。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>在八达岭<a href="/beijing-travel-guide/landmarks/badaling/guancheng.html">关城</a>东侧的山崖之间，卧着一块天然巨石，名曰<strong>望京石</strong>。石身浑厚，登之可远眺东南方向——那里，是一百多里外的北京城。巨石周围的山崖上，还散落着&quot;天险&quot;&quot;地利&quot;等摩崖题刻，字迹历经风雨而筋骨犹存，与巍峨的关城互为表里。</p><p>如果说关城与<a href="/beijing-travel-guide/landmarks/badaling/dilou.html">敌楼</a>写的是明代边防，那么望京石与八达岭山脚的遗迹，写的则是晚清以降的近代中国：慈禧西逃的仓皇背影、詹天佑与中国人自建的第一条铁路，都发生在这片山谷之中。</p><p>登城归来路过此处，不妨放慢脚步——长城的故事到关城为止，而八达岭的故事，还一直延伸到了山脚下那条百年铁轨上。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>望京石</strong></td><td style="text-align:left;">关城东侧天然巨石，传为登石望京之处</td></tr><tr><td style="text-align:left;"><strong>摩崖题刻</strong></td><td style="text-align:left;">&quot;天险&quot;&quot;地利&quot;等，镌于关城周边崖壁（明清题刻）</td></tr><tr><td style="text-align:left;"><strong>京张铁路</strong></td><td style="text-align:left;">1905年开工、1909年通车，中国人自主修建的第一条干线铁路</td></tr><tr><td style="text-align:left;"><strong>青龙桥&quot;人&quot;字形线路</strong></td><td style="text-align:left;">位于八达岭脚下，詹天佑的经典设计</td></tr><tr><td style="text-align:left;"><strong>詹天佑纪念地</strong></td><td style="text-align:left;">青龙桥车站铜像与詹天佑纪念馆，免费开放</td></tr><tr><td style="text-align:left;"><strong>京张高铁</strong></td><td style="text-align:left;">2019年通车，八达岭长城站深埋地下102米</td></tr><tr><td style="text-align:left;"><strong>老站房</strong></td><td style="text-align:left;">青龙桥百年车站，全国重点文物保护单位</td></tr></tbody></table><h3 id="望京石与摩崖题刻" tabindex="-1">望京石与摩崖题刻 <a class="header-anchor" href="#望京石与摩崖题刻" aria-label="Permalink to &quot;望京石与摩崖题刻&quot;">​</a></h3><p><strong>望京石</strong>本身并无雕琢，胜在其位与其事：它恰在出关西行必经之路旁，登石回望，关山阻隔之外的京师方向隐约可辨。千百年来，戍卒商旅经此出塞，回望故土的最后一点高处，往往就是这块石头。</p><p>崖壁上的**&quot;天险&quot;**二字摩崖，则是对八达岭地势最精炼的概括——两山夹峙、一夫当关，古人把对这片山河的判断，直接刻进了石头里。与之相伴的&quot;地利&quot;等题刻，同属明清时期往来官员、文人的手笔，是题刻者的&quot;到此一游&quot;，也是后人的历史路标。</p><p>石与字都未经精细雕琢，粗粝中带着边关气质——比起城楼的规整，这些野性的刻痕更接近八达岭作为军事要塞的本来面目。</p><h3 id="青龙桥-人-字形线路" tabindex="-1">青龙桥&quot;人&quot;字形线路 <a class="header-anchor" href="#青龙桥-人-字形线路" aria-label="Permalink to &quot;青龙桥&quot;人&quot;字形线路&quot;">​</a></h3><p>山脚下的<strong>青龙桥&quot;人&quot;字形线路</strong>是另一处必看奇观：京张铁路穿越八达岭时坡度极陡，詹天佑在此设计出&quot;人&quot;字形折返线——列车北上至青龙桥后，改换机车方向，先向东北、再折向西北，如人字一撇一捺爬上山岭，以&quot;距离换高度&quot;化解了越岭难题。</p><p>爬坡时更有巧思：两台机车一前一后，一台牵引、一台助推，行至折返点再互换角色。这是中国铁路工程史上教科书级的一笔，也是百年前中国工程师向世界交出的答卷。</p><p>如今，&quot;人&quot;字形线路仍是老京张线（京包铁路）的一部分，青龙桥车站仍在运营——百年设计至今服役，本身就是对詹天佑最好的纪念。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="慈禧登石望京" tabindex="-1">慈禧登石望京 <a class="header-anchor" href="#慈禧登石望京" aria-label="Permalink to &quot;慈禧登石望京&quot;">​</a></h3><p>1900年（庚子年），八国联军攻入北京，慈禧太后携光绪帝微服出逃，沿关沟古道西奔西安。相传銮驾行至八达岭关城之侧，太后登上这块巨石，回望烟尘中的京师，良久不语——望京石因此得名。</p><p>此说虽为民间流传，但另一重功能同样可信：此石地处要冲、视野开阔，历来是兵家登临瞭望京师方向、观察关沟动静的望所。一块石头，叠印着家国之痛与兵家之智。</p><p>耐人寻味的是，庚子之变后不久，詹天佑便率队来到同一片山谷勘测铁路——望京石目送的，正是一个旧时代仓皇谢幕、新时代踉跄登场的转折时刻。</p><h3 id="詹天佑与-人-字形线路" tabindex="-1">詹天佑与&quot;人&quot;字形线路 <a class="header-anchor" href="#詹天佑与-人-字形线路" aria-label="Permalink to &quot;詹天佑与&quot;人&quot;字形线路&quot;">​</a></h3><p>1905年，京张铁路开工。这条从北京通往张家口的铁路，要穿越八达岭的崇山峻岭，英俄工程师曾断言中国人无力自建。总工程师<strong>詹天佑</strong>踏勘山势，在青龙桥创造性地铺设&quot;人&quot;字形折返线，并配合两台机车一拉一推翻越山岭，使线路成功越岭。</p><p>1909年，京张铁路提前两年建成通车，是中国第一条完全由中国人自行设计、施工的干线铁路。青龙桥车站旁，詹天佑铜像至今目送列车穿山而过；老站房、旧铁轨与&quot;人&quot;字形道岔原址犹存，是全国重点文物保护单位。</p><h3 id="百年京张的对照" tabindex="-1">百年京张的对照 <a class="header-anchor" href="#百年京张的对照" aria-label="Permalink to &quot;百年京张的对照&quot;">​</a></h3><p>老京张铁路通车110年后的2019年，<strong>京张高铁</strong>建成通车，八达岭长城站深埋地下102米，恰从青龙桥&quot;人&quot;字形线路下方穿越——从时速35公里到350公里，从&quot;人&quot;字形折返到一洞穿山，两条铁路在山谷间完成了一场跨越百年的对话。詹天佑当年的夙愿，以他未必想象得到的方式圆了。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>望京石</strong>：登石东南远眺，体会古人&quot;望京&quot;的视角与心境。</li><li><strong>&quot;天险&quot;&quot;地利&quot;摩崖</strong>：关城崖壁上的大字题刻，是八达岭地势的千年评语。</li><li><strong>青龙桥&quot;人&quot;字形线路</strong>：在八达岭脚下看铁路如何&quot;撇捺登山&quot;，詹天佑铜像与老站房就在现场。</li><li><strong>詹天佑纪念馆</strong>：免费开放，系统陈列京张铁路的勘测、建设与通车史料。</li><li><strong>百年对照</strong>：老京张与新京张同谷并存，是中国铁路史最直观的现场教材。</li><li><strong>关沟古道遗韵</strong>：望京石所在一线即昔日车马出塞的古道，缓步其间可想见当年情景。</li><li><strong>题刻寻字</strong>：除&quot;天险&quot;外，崖壁间还散有&quot;地利&quot;等题刻，值得放慢脚步细寻。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>位置顺路</strong>：望京石与摩崖题刻就在关城旁，下城后经<a href="/beijing-travel-guide/landmarks/badaling/guancheng.html">关城</a>步行即达，无需专程绕路。</li><li><strong>青龙桥顺游</strong>：青龙桥及詹天佑纪念馆位于八达岭山脚，免费开放，可与长城组成一日行程；自驾或乘S2线市郊铁路沿线而来均可。</li><li><strong>别错过题刻</strong>：&quot;天险&quot;摩崖就在路旁崖壁，抬头即见，许多人爬完长城竟未留意。</li><li><strong>拍照时机</strong>：崖壁题刻侧光时立体感最强，上午或傍晚拍摄效果最佳。</li><li><strong>S2线车上看</strong>：乘S2线市郊铁路往来八达岭，列车行驶在老京张线上，车窗外即是百年铁路遗迹，本身就是流动的风景。</li><li><strong>护石勿刻</strong>：望京石与摩崖题刻均为历史遗存，切勿刻画攀踏石面。</li><li><strong>组合建议</strong>：&quot;登城 → 望京石 → 博物馆&quot;半天即可；加上青龙桥则需安排一整天。</li><li><strong>带望远镜</strong>：想看清山脊上的墩台残迹或&quot;人&quot;字形线路全貌，小型望远镜很有帮助。</li><li><strong>行程收尾</strong>：访罢望京石，可回到关城脚下的<a href="/beijing-travel-guide/landmarks/badaling/changcheng-museum.html">中国长城博物馆</a>为一日之行收尾。</li></ul><hr><p><strong>📍 位置</strong>：八达岭关城东侧崖间；青龙桥遗迹在八达岭脚下 <strong>⏱️ 建议游览</strong>：望京石15-20分钟；含青龙桥约半天 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/badaling/beibalou.html">北八楼与好汉坡</a>（登顶归来顺路寻访） <strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/badaling/changcheng-museum.html">中国长城博物馆</a>（关城脚下，免费） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/badaling/">八达岭长城概览</a></p>',33)])])}const p=a(l,[["render",n]]);export{q as __pageData,p as default};
